  1	import * as React from 'react';
  2	import { IRow, ThProps } from '@patternfly/react-table';
  3	import { Button, ButtonVariant, TextInput } from '@patternfly/react-core';
  4	import { isValidRequestHeaderName, isValidRequestAuthClaimName } from '../../../../helpers/ValidationHelpers';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { PFColors } from '../../../../components/Pf/PfColors';
  7	import { isValidIp } from '../../../../utils/IstioConfigUtils';
  8	import { isValid } from 'utils/Common';
  9	import { SimpleTable } from 'components/Table/SimpleTable';
 10	import { KialiIcon } from 'config/KialiIcon';
 11	import { t, useKialiTranslation } from 'utils/I18nUtils';
 12	
 13	export type Condition = {
 14	  key: string;
 15	  notValues?: string[];
 16	  values?: string[];
 17	};
 18	
 19	type Props = {
 20	  onAddCondition: (condition: Condition) => void;
 21	};
 22	
 23	const columns: ThProps[] = [
 24	  {
 25	    title: t('Condition Key'),
 26	    width: 30
 27	  },
 28	  {
 29	    title: t('Values'),
 30	    width: 30
 31	  },
 32	  {
 33	    title: t('Not Values'),
 34	    width: 30
 35	  }
 36	];
 37	
 38	const noValidKeyStyle = kialiStyle({
 39	  color: PFColors.Red100
 40	});
 41	
 42	const conditionFixedKeys = [
 43	  'source.ip',
 44	  'remote.ip',
 45	  'source.namespace',
 46	  'source.principal',
 47	  'request.auth.principal',
 48	  'request.auth.audiences',
 49	  'request.auth.presenter',
 50	  'destination.ip',
 51	  'destination.port',
 52	  'connection.sni'
 53	];
 54	
 55	const conditionIpAddressKeys = ['source.ip', 'remote.ip', 'destination.ip'];
 56	
 57	export const ConditionBuilder: React.FC<Props> = (props: Props) => {
 58	  const [condition, setCondition] = React.useState<Condition>({ key: '' });
 59	
 60	  const { t } = useKialiTranslation();
 61	
 62	  const onAddNewConditionKey = (_event: React.FormEvent, key: string): void => {
 63	    const newCondition = { ...condition };
 64	    newCondition.key = key;
 65	
 66	    setCondition(newCondition);
 67	  };
 68	
 69	  const onAddNewValues = (_event: React.FormEvent, value: string): void => {
 70	    const newCondition = { ...condition };
 71	    newCondition.values = value.length === 0 ? [] : value.split(',');
 72	
 73	    setCondition(newCondition);
 74	  };
 75	
 76	  const onAddNewNotValues = (_event: React.FormEvent, notValues: string): void => {
 77	    const newCondition = { ...condition };
 78	    newCondition.notValues = notValues.length === 0 ? [] : notValues.split(',');
 79	
 80	    setCondition(newCondition);
 81	  };
 82	
 83	  const onAddConditionToList = (): void => {
 84	    const conditionItem = condition;
 85	
 86	    setCondition({ key: '' });
 87	    props.onAddCondition(conditionItem);
 88	  };
 89	
 90	  const isValidKey = (key: string): boolean => {
 91	    if (key.length === 0) {
 92	      return false;
 93	    }
 94	
 95	    if (conditionFixedKeys.includes(key)) {
 96	      return true;
 97	    }
 98	
 99	    if (key.startsWith('request.headers')) {
100	      return isValidRequestHeaderName(key);
101	    }
102	
103	    if (key.startsWith('experimental.envoy.filters.')) {
104	      return true;
105	    }
106	
107	    if (key.startsWith('request.auth.claims[')) {
108	      return isValidRequestAuthClaimName(key);
109	    }
110	
111	    return false;
112	  };
113	
114	  // Helper to mark invalid any of the fields: key, values, notValues with helper text
115	  const isValidCondition = (): [boolean, boolean, boolean, string] => {
116	    const key = condition.key;
117	    const isValid = isValidKey(key);
118	
119	    if (!isValid) {
120	      return [false, true, true, t('Condition Key not supported')];
121	    }
122	
123	    const values = condition.values;
124	    const notValues = condition.notValues;
125	
126	    if ((!values || values.length === 0) && (!notValues || notValues.length === 0)) {
127	      return [true, false, false, t('Values and NotValues cannot be empty')];
128	    }
129	
130	    if (conditionIpAddressKeys.includes(key)) {
131	      // If some value is not an IP, then is not valid
132	      const valuesValid = values ? !values.some(value => !isValidIp(value)) : true;
133	      const notValuesValid = notValues ? !notValues.some(value => !isValidIp(value)) : true;
134	      return [true, valuesValid, notValuesValid, t('Not valid IP')];
135	    }
136	
137	    return [true, true, true, ''];
138	  };
139	
140	  const rows = (validKey: boolean, validValues: boolean, validNotValues: boolean, validText: string): IRow[] => {
141	    return [
142	      {
143	        key: 'conditionKeyNew',
144	        cells: [
145	          <>
146	            <TextInput
147	              value={condition.key}
148	              type="text"
149	              id="addNewConditionKey"
150	              key="addNewConditionKey"
151	              aria-describedby={t('Add new condition key')}
152	              name="addNewConditionKey"
153	              onChange={onAddNewConditionKey}
154	              validated={isValid(validKey)}
155	            />
156	
157	            {!validKey && (
158	              <div key="hostsHelperText" className={noValidKeyStyle}>
159	                {validText}
160	              </div>
161	            )}
162	          </>,
163	          <>
164	            <TextInput
165	              value={condition.values ? condition.values.join(',') : ''}
166	              type="text"
167	              id="addNewValues"
168	              key="addNewValues"
169	              aria-describedby={t('Add new condition values')}
170	              name="addNewConditionValues"
171	              onChange={onAddNewValues}
172	            />
173	
174	            {!validValues && (
175	              <div key="hostsHelperText" className={noValidKeyStyle}>
176	                {validText}
177	              </div>
178	            )}
179	          </>,
180	          <>
181	            <TextInput
182	              value={condition.notValues ? condition.notValues.join(',') : ''}
183	              type="text"
184	              id="addNewNotValues"
185	              key="addNewNotValues"
186	              aria-describedby={t('Add new condition not values')}
187	              name="addNewNotValues"
188	              onChange={onAddNewNotValues}
189	            />
190	
191	            {!validNotValues && (
192	              <div key="hostsHelperText" className={noValidKeyStyle}>
193	                {validText}
194	              </div>
195	            )}
196	          </>
197	        ]
198	      }
199	    ];
200	  };
201	
202	  const [validKey, validValues, validNotValues, validText] = isValidCondition();
203	  const validCondition = validKey && validValues && validNotValues;
204	
205	  return (
206	    <>
207	      <SimpleTable
208	        label={t('Condition Builder')}
209	        columns={columns}
210	        rows={rows(validKey, validValues, validNotValues, validText)}
211	      />
212	
213	      <Button
214	        variant={ButtonVariant.link}
215	        icon={<KialiIcon.AddMore />}
216	        isDisabled={!validCondition}
217	        onClick={onAddConditionToList}
218	      >
219	        {t('Add Condition to When List')}
220	      </Button>
221	    </>
222	  );
223	};

